local mode = "Once"
local t = 0
local idx = 1
local lastTime = frames[#frames].Time
local connection

local function smoothCFrame(a, b, alpha)
    local pos = a.Position:Lerp(b.Position, alpha)
    local look = a.LookVector:Lerp(b.LookVector, alpha).Unit
    local up = a.UpVector:Lerp(b.UpVector, alpha).Unit
    local right = look:Cross(up).Unit
    up = right:Cross(look).Unit
    return CFrame.fromMatrix(pos, right, up)
end

connection = RunService.RenderStepped:Connect(function(dt)
    t = t + dt
    if mode == "Once" and t > lastTime then
        cam.CameraType = originalCamType
        hum.AutoRotate = originalAutoRotate
        hum.WalkSpeed = originalWalkSpeed
        hum.HipHeight = originalHipHeight
        connection:Disconnect()
        return
    elseif mode == "Loop" then
        t = t % lastTime
    end

    while idx < #frames and t >= frames[idx + 1].Time do idx = idx + 1 end
    if idx >= #frames then idx = 1 end

    local a = frames[idx]
    local b = frames[idx + 1] or frames[1]
    local alpha = math.clamp((t - a.Time) / (b.Time - a.Time), 0, 1)

    local pos = a.Pos:Lerp(b.Pos, alpha)
    local move = a.Move:Lerp(b.Move, alpha)
    local fov = a.FOV + (b.FOV - a.FOV) * alpha
    local cf = smoothCFrame(a.CFrame, b.CFrame, alpha)

    cam.CFrame = cf
    cam.FieldOfView = fov

    hum.WalkSpeed = a.WalkSpeed
    hum.HipHeight = originalHipHeight

    -- Rotasi karakter lebih natural
    local lookFlat = Vector3.new(cf.LookVector.X, 0, cf.LookVector.Z)
    if lookFlat.Magnitude > 0.01 then
        lookFlat = lookFlat.Unit
        hrp.CFrame = CFrame.lookAt(pos, pos + lookFlat * 10)
    end

    hum:Move(move, true)
    hrp.AssemblyLinearVelocity = a.Vel:Lerp(b.Vel, alpha)
end)
